const raw = $input.first().json;
const agent = raw.agent || 'general';
const task = raw.task || '';
const context = raw.context || '';
const explicitComplexity = raw.complexity;

// If no explicit complexity score provided, derive from task heuristics
let complexity = explicitComplexity;
if (!complexity) {
  const taskLower = task.toLowerCase();
  // High complexity signals
  if (/strateg|architect|design|plan|reason|analyze|compar|synthesiz|research|investigat|why|how.{0,20}work/i.test(task)) {
    complexity = 8;
  } else if (/summar|explain|draft|write|creat|list|find|search|lookup|format|translat/i.test(task)) {
    complexity = 5;
  } else {
    complexity = 3;
  }
}
complexity = Math.max(1, Math.min(10, Number(complexity)));

const tier = complexity <= 3 ? 'haiku' : complexity <= 7 ? 'sonnet' : 'opus';
const model = {
  haiku: 'anthropic/claude-haiku-4.5',
  sonnet: 'anthropic/claude-sonnet-4.5',
  opus: 'anthropic/claude-opus-4-5'
}[tier];

const systemPrompt = `You are a specialized ${agent} agent. Be direct, thorough, and precise. Respond in the same language as the task.

Context from the user's conversation:
${context}`;

return [{ json: { agent, task, context, complexity, tier, model, systemPrompt } }];

